    counted(n)
    return counted.call_count

def count_divisors(n):
    sqrt_n = sqrt(n)
    k, divisors = 1, 0
    while k < sqrt_n:
        if n % k == 0:
            divisors += 2
        k += 1
    if k * k == n:
        divisors += 1
    return divisors

